svg.script:
// Perlin noise implementation
class PerlinNoise {
  constructor(seed = Math.random() * 10000) {
    this.p = [];
    for (let i = 0; i < 256; i++) this.p[i] = i;
    // Shuffle with seed
    let n = seed;
    for (let i = 255; i > 0; i--) {
      n = (n * 16807) % 2147483647;
      const j = n % (i + 1);
      [this.p[i], this.p[j]] = [this.p[j], this.p[i]];
    }
    this.p = this.p.concat(this.p);
  }

  fade(t) { return t * t * t * (t * (t * 6 - 15) + 10); }
  lerp(a, b, t) { return a + t * (b - a); }
  grad(hash, x) {
    return (hash & 1) === 0 ? x : -x;
  }

  noise1D(x) {
    const xi = Math.floor(x) & 255;
    const xf = x - Math.floor(x);
    const u = this.fade(xf);
    return this.lerp(
      this.grad(this.p[xi], xf),
      this.grad(this.p[xi + 1], xf - 1),
      u
    );
  }
}

// Each leg gets its own noise generator and parameters
const legs = [
  { el: document.getElementById('leg0'), noise: new PerlinNoise(1), baseX: -16, baseY: 32, freqX: 0.8, freqY: 1.2, ampX: 3, ampY: 6, phase: 0 },
  { el: document.getElementById('leg1'), noise: new PerlinNoise(2), baseX: -10, baseY: 32, freqX: 1.1, freqY: 0.9, ampX: 2.5, ampY: 5, phase: 0.7 },
  { el: document.getElementById('leg2'), noise: new PerlinNoise(3), baseX: 6, baseY: 32, freqX: 0.9, freqY: 1.0, ampX: 2.5, ampY: 5, phase: 1.4 },
  { el: document.getElementById('leg3'), noise: new PerlinNoise(4), baseX: 12, baseY: 32, freqX: 1.0, freqY: 1.3, ampX: 3, ampY: 6, phase: 2.1 }
];

let time = 0;

function animate() {
  if (window.isPaused) { requestAnimationFrame(animate); return; }
  time += 0.016; // ~60fps

  legs.forEach(leg => {
    // Perlin noise for organic motion
    const noiseX = leg.noise.noise1D(time * leg.freqX + leg.phase);
    const noiseY = leg.noise.noise1D(time * leg.freqY + leg.phase + 100);

    // Oscillation base + noise modulation
    const oscX = Math.sin(time * 2 + leg.phase) * 0.5;
    const oscY = Math.sin(time * 3 + leg.phase) * 0.5;

    // Combined translation
    const dx = (noiseX + oscX) * leg.ampX;
    const dy = (noiseY + oscY) * leg.ampY;

    // Mirror effect (scale flip based on noise)
    const scaleX = noiseX > 0 ? 1 : -1;

    leg.el.setAttribute('x', leg.baseX + dx);
    leg.el.setAttribute('y', leg.baseY + Math.abs(dy));
  });

  requestAnimationFrame(animate);
}

animate();
